<script setup lang="ts">
import{computed,onMounted,ref,watch}from"vue";import{Search,MapPin,Building2,ChevronRight}from"lucide-vue-next";import{api,type Department,type Doctor,type Hospital}from"../api";import PageHeader from"../components/PageHeader.vue";
const hospitals=ref<Hospital[]>([]),departments=ref<Department[]>([]),departmentDoctors=ref<Doctor[]>([]),selected=ref<number>(),keyword=ref("");const displayed=computed(()=>selected.value?hospitals.value.filter(h=>departmentDoctors.value.some(d=>d.hospitalId===h.id)):hospitals.value);
async function load(){hospitals.value=await api.hospitals(keyword.value)}async function selectDepartment(id?:number){selected.value=id;departmentDoctors.value=id?await api.doctors({departmentId:id}):[]}
onMounted(async()=>{await Promise.all([load(),api.departments().then(x=>departments.value=x)])});let timer:number;watch(keyword,()=>{clearTimeout(timer);timer=window.setTimeout(load,250)});
</script>
<template><main><PageHeader title="找医院"/><div class="search-box"><Search/><input v-model="keyword" placeholder="搜索医院、地区"/></div><div class="region"><MapPin/> 当前地区：<b>北京市</b></div><div class="hospital-layout"><aside><button :class="{active:!selected}" @click="selectDepartment()">全部科室</button><button v-for="d in departments.slice(0,12)" :key="d.id" :class="{active:selected===d.id}" @click="selectDepartment(d.id)">{{d.name}}</button></aside><section class="hospital-results"><article v-for="h in displayed" :key="h.id" @click="$router.push(`/hospitals/${h.id}`)"><span class="hospital-icon"><Building2/></span><div><h3>{{h.name}}</h3><p><i>{{h.level}}</i><i>{{h.type||'综合医院'}}</i></p><small>地址：{{h.city}}{{h.district}}{{h.address}}</small></div><ChevronRight/></article><div v-if="!displayed.length" class="empty">暂无匹配医院</div></section></div></main></template>
